        }
      },
      selected_sections: {
        type: 'array',
        items: {
          type: 'object',
          properties: {
            file: { type: 'string' },
            section_id: { type: 'string' },
            relevance: { type: 'string', enum: ['high', 'partial'] },
            reason: { type: 'string' }
          },
          required: ['file', 'section_id', 'relevance', 'reason']
        }
      },
      excluded_sections: {
